
<script setup lang="ts">
import {onMounted,ref} from 'vue'
import {useRouter} from 'vue-router'
import GlobalHeader from '../components/global/GlobalHeader.vue'
import GlobalFooter from '../components/global/GlobalFooter.vue'
import {useAuth} from '../composables/useAuth'
import {adminApi} from '../services/user-api'
const router=useRouter(),auth=useAuth(),tab=ref('overview'),loading=ref(true),error=ref(''),overview=ref<any>(),users=ref<any>({results:[]}),reviews=ref<any[]>([]),logs=ref<any>({audit:[],sync:[]}),query=ref(''),notice=ref('')
async function load(){loading.value=true;error.value='';try{if(!auth.ready.value)await auth.refresh();if(auth.user.value?.role!=='admin'){router.replace('/');return}overview.value=await adminApi.overview();users.value=await adminApi.users();reviews.value=await adminApi.reviews();logs.value=await adminApi.logs()}catch(e){error.value=e instanceof Error?e.message:'后台加载失败'}finally{loading.value=false}}
async function searchUsers(){users.value=await adminApi.users(query.value)}
async function updateUser(user:any,field:'role'|'status',value:string){await adminApi.updateUser(user.id,{[field]:value});notice.value='用户状态已更新';await load()}
async function moderate(entry:any,status:string){await adminApi.moderate(entry.id,status);notice.value='短评审核状态已更新';reviews.value=await adminApi.reviews()}
onMounted(load)
</script>
<template><div class="min-h-screen bg-background text-on-surface"><GlobalHeader/><main class="mx-auto max-w-[1400px] px-4 pb-20 pt-[82px] md:px-8"><header class="mb-8 flex flex-col justify-between gap-5 border-b border-white/10 pb-6 md:flex-row md:items-end"><div><p class="text-xs font-bold tracking-[.2em] text-primary">MOVIESCOPE ADMIN</p><h1 class="mt-2 text-4xl font-extrabold">管理后台</h1><p class="mt-2 text-sm text-on-surface-variant">管理用户、站内短评、数据缓存与接口运行状态。</p></div><p v-if="notice" class="text-sm text-primary">{{notice}}</p></header><div v-if="loading" class="py-24 text-center text-on-surface-variant">后台数据加载中…</div><div v-else-if="error" class="rounded-xl border border-red-400/20 bg-red-400/10 p-6 text-red-200">{{error}}</div><div v-else class="grid gap-8 lg:grid-cols-[220px_1fr]"><aside><nav class="sticky top-20 space-y-2"><button v-for="item in [['overview','数据概览','dashboard'],['users','用户管理','group'],['reviews','短评审核','reviews'],['logs','数据源日志','monitor_heart']]" :key="item[0]" class="admin-nav" :class="tab===item[0]?'active':''" @click="tab=item[0]"><span class="material-symbols-outlined">{{item[2]}}</span>{{item[1]}}</button></nav></aside><section class="min-w-0"><template v-if="tab==='overview'"><div class="grid gap-4 sm:grid-cols-2 xl:grid-cols-4"><div class="metric"><span>注册用户</span><strong>{{overview.users.count||0}}</strong><small>{{overview.users.admins||0}} 位管理员</small></div><div class="metric"><span>观影记录</span><strong>{{overview.entries.count||0}}</strong><small>{{overview.entries.ratings||0}} 条评分</small></div><div class="metric"><span>站内短评</span><strong>{{overview.reviews.count||0}}</strong><small>{{overview.reviews.hidden||0}} 条已隐藏</small></div><div class="metric"><span>有效会话</span><strong>{{overview.activeSessions||0}}</strong><small>24 小时接口错误 {{overview.providerErrors24h||0}}</small></div></div><div class="mt-8 rounded-xl border border-white/5 bg-surface-container p-6"><h2 class="text-xl font-bold">SQL 缓存状态</h2><div class="mt-5 grid gap-3 sm:grid-cols-2 lg:grid-cols-3"><div v-for="item in overview.cache" :key="item.provider" class="rounded-lg bg-surface-container-high p-4"><b>{{item.provider}}</b><p class="mt-2 text-sm text-on-surface-variant">{{item.count}} 条缓存 · {{item.active}} 条有效</p></div></div></div></template><template v-else-if="tab==='users'"><div class="mb-5 flex gap-3"><input v-model="query" class="admin-input" placeholder="搜索用户名、邮箱或显示名称" @keydown.enter="searchUsers"><button class="rounded-lg bg-primary-container px-5 font-bold text-on-primary-container" @click="searchUsers">搜索</button></div><div class="overflow-x-auto rounded-xl border border-white/5"><table class="admin-table"><thead><tr><th>用户</th><th>邮箱</th><th>角色</th><th>状态</th><th>注册时间</th></tr></thead><tbody><tr v-for="user in users.results" :key="user.id"><td><div class="flex items-center gap-3"><img :src="user.avatarUrl" class="h-10 w-10 rounded-full object-cover"><div><b>{{user.displayName}}</b><p class="text-xs text-outline">@{{user.username}}</p></div></div></td><td>{{user.email}}</td><td><select :value="user.role" class="table-select" @change="updateUser(user,'role',($event.target as HTMLSelectElement).value)"><option value="user">用户</option><option value="admin">管理员</option></select></td><td><select :value="user.status" class="table-select" @change="updateUser(user,'status',($event.target as HTMLSelectElement).value)"><option value="active">正常</option><option value="suspended">停用</option></select></td><td>{{new Date(user.createdAt).toLocaleDateString('zh-CN')}}</td></tr></tbody></table></div></template><template v-else-if="tab==='reviews'"><div class="space-y-4"><article v-for="entry in reviews" :key="entry.id" class="rounded-xl border border-white/5 bg-surface-container p-5"><div class="flex flex-wrap justify-between gap-4"><div><b>{{entry.user.displayName}}</b><span class="ml-2 text-xs text-outline">@{{entry.user.username}}</span><h3 class="mt-2 text-lg font-bold">{{entry.title}} <span v-if="entry.rating" class="text-primary">{{entry.rating}} / 10</span></h3></div><span class="rounded-full px-3 py-1 text-xs" :class="entry.reviewStatus==='published'?'bg-green-400/10 text-green-300':'bg-red-400/10 text-red-300'">{{entry.reviewStatus==='published'?'公开':'已隐藏'}}</span></div><p class="mt-4 whitespace-pre-line text-sm leading-6 text-on-surface-variant">{{entry.reviewText}}</p><div class="mt-4 flex gap-3"><button class="text-sm font-bold text-primary" @click="moderate(entry,'published')">恢复公开</button><button class="text-sm font-bold text-red-300" @click="moderate(entry,'hidden')">隐藏短评</button></div></article></div></template><template v-else><div class="space-y-8"><section><h2 class="mb-4 text-xl font-bold">管理员操作日志</h2><div class="space-y-2"><div v-for="item in logs.audit" :key="item.id" class="log-row"><span>{{item.adminUsername}} · {{item.action}}</span><time>{{new Date(item.created_at).toLocaleString('zh-CN')}}</time></div></div></section><section><h2 class="mb-4 text-xl font-bold">数据源同步日志</h2><div class="space-y-2"><div v-for="item in logs.sync" :key="item.id" class="log-row"><span><b :class="item.status==='error'?'text-red-300':'text-green-300'">{{item.status}}</b> · {{item.provider}} · {{item.operation}}</span><time>{{item.durationMs}} ms · {{new Date(item.createdAt).toLocaleString('zh-CN')}}</time></div></div></section></div></template></section></div></main><GlobalFooter/></div></template>
<style scoped>.admin-nav{display:flex;width:100%;align-items:center;gap:12px;border-radius:8px;padding:13px 15px;color:#c5c7ce}.admin-nav:hover{background:#282a30;color:#e2e2e8}.admin-nav.active{background:#f5c518;color:#111;font-weight:700}.metric{display:flex;min-height:150px;flex-direction:column;border:1px solid rgba(255,255,255,.05);border-radius:12px;background:#1d2025;padding:22px}.metric span,.metric small{color:#c5c7ce}.metric strong{margin:14px 0 8px;font-size:34px;color:#f5c518}.admin-input{min-width:0;flex:1;border:1px solid rgba(255,255,255,.1);border-radius:8px;background:#1d2025;padding:12px;outline:none}.admin-table{width:100%;min-width:800px;border-collapse:collapse;background:#1d2025}.admin-table th,.admin-table td{border-bottom:1px solid rgba(255,255,255,.06);padding:14px;text-align:left;font-size:13px}.admin-table th{color:#c5c7ce}.table-select{border-radius:6px;background:#282a30;padding:8px}.log-row{display:flex;justify-content:space-between;gap:20px;border-bottom:1px solid rgba(255,255,255,.05);padding:12px 0;font-size:13px}.log-row time{color:#777b84}</style>
